import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;
import javax.xml.soap.MessageFactory;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPPart;
import javax.xml.soap.SOAPEnvelope;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.SOAPElement;
import java.util.logging.Logger;
import java.util.logging.Level;

public class EnterpriseXMLProcessor {
    private static final Logger logger = Logger.getLogger(EnterpriseXMLProcessor.class.getName());
    private static final int MAX_DOCUMENT_SIZE = 10 * 1024 * 1024; // 10MB
    private static final int MAX_ENTITY_EXPANSION = 10000;
    
    private final DocumentBuilderFactory dbf;
    
    public EnterpriseXMLProcessor() {
        dbf = DocumentBuilderFactory.newInstance();
        dbf.setNamespaceAware(true);
        dbf.setIgnoringElementContentWhitespace(true);
        dbf.setExpandEntityReferences(false);
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setFeature("http://apache.org/xml/features/dom/defer-node-expansion", false);
        dbf.setFeature("http://apache.org/xml/features/validation/schema", false);
        dbf.setFeature("http://apache.org/xml/features/validation/dtd", false);
        dbf.setFeature("http://apache.org/xml/features/secure-processing", true);
        dbf.setAttribute("http://apache.org/xml/properties/dom/entity-resolver", new SecureEntityResolver());
    }
    
    public Document processSOAPMessage(String soapMessage) throws Exception {
        try {
            SOAPMessage soap = MessageFactory.newInstance().createMessage(null, 
                new ByteArrayInputStream(soapMessage.getBytes(StandardCharsets.UTF_8)));
            SOAPBody body = soap.getSOAPBody();
            
            if (body.hasFault()) {
                throw new Exception("SOAP Fault detected: " + body.getFault().getFaultString());
            }
            
            String xmlContent = extractXMLFromSOAP(body);
            return parseXMLDocument(xmlContent);
            
        } catch (Exception e) {
            logger.log(Level.SEVERE, "Error processing SOAP message", e);
            throw e;
        }
    }
    
    private String extractXMLFromSOAP(SOAPBody body) throws Exception {
        StringBuilder xmlContent = new StringBuilder();
        NodeList children = body.getChildElements();
        
        for (int i = 0; i < children.getLength(); i++) {
            Element element = (Element) children.item(i);
            xmlContent.append("<").append(element.getNodeName()).append(">");
            xmlContent.append(element.getTextContent());
            xmlContent.append("</").append(element.getNodeName()).append(">");
        }
        
        return xmlContent.toString();
    }
    
    private Document parseXMLDocument(String xmlContent) throws Exception {
        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            throw new IllegalArgumentException("XML content cannot be null or empty");
        }
        
        try {
            DocumentBuilder db = dbf.newDocumentBuilder();
            db.setErrorHandler(new SecureErrorHandler());
            
            InputStream inputStream = new ByteArrayInputStream(xmlContent.getBytes(StandardCharsets.UTF_8));
            Document document = db.parse(inputStream);
            
            validateDocumentSize(document);
            validateEntityExpansion(document);
            
            return document;
            
        } catch (ParserConfigurationException e) {
            throw new Exception("Parser configuration error", e);
        } catch (IOException e) {
            throw new Exception("IO error during parsing", e);
        }
    }
    
    private void validateDocumentSize(Document document) throws Exception {
        int estimatedSize = estimateDocumentSize(document);
        if (estimatedSize > MAX_DOCUMENT_SIZE) {
            throw new Exception("Document size exceeds maximum allowed: " + 
                MAX_DOCUMENT_SIZE + " bytes");
        }
    }
    
    private void validateEntityExpansion(Document document) throws Exception {
        int entityCount = countEntities(document);
        if (entityCount > MAX_ENTITY_EXPANSION) {
            throw new Exception("Entity expansion exceeds maximum allowed: " + 
                MAX_ENTITY_EXPANSION);
        }
    }
    
    private int estimateDocumentSize(Document document) {
        return document.toString().getBytes(StandardCharsets.UTF_8).length;
    }
    
    private int countEntities(Element element) {
        int count = 0;
        NodeList children = element.getChildNodes();
        
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                count++;
                count += countEntities((Element) children.item(i));
            }
        }
        
        return count;
    }
    
    public void processLargeXMLPayload(String xmlPayload) throws Exception {
        if (xmlPayload == null || xmlPayload.isEmpty()) {
            throw new IllegalArgumentException("XML payload cannot be null or empty");
        }
        
        Document document = parseXMLDocument(xmlPayload);
        processXMLStructure(document);
    }
    
    private void processXMLStructure(Document document) {
        Element root = document.getDocumentElement();
        processElement(root, 0);
    }
    
    private void processElement(Element element, int depth) {
        if (depth > 100) {
            throw new RuntimeException("Maximum nesting depth exceeded");
        }
        
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                Element childElement = (Element) children.item(i);
                processElement(childElement, depth + 1);
            }
        }
    }
    
    public static class SecureEntityResolver implements org.xml.sax.EntityResolver {
        @Override
        public org.xml.sax.InputSource resolveEntity(String publicId, String systemId) {
            return new org.xml.sax.InputSource(new ByteArrayInputStream(new byte[0]));
        }
    }
    
    public static class SecureErrorHandler implements org.xml.sax.ErrorHandler {
        @Override
        public void warning(org.xml.sax.SAXParseException exception) {
            logger.log(Level.WARNING, "XML Warning: " + exception.getMessage());
        }
        
        @Override
        public void error(org.xml.sax.SAXParseException exception) {
            logger.log(Level.SEVERE, "XML Error: " + exception.getMessage());
        }
        
        @Override
        public void fatalError(org.xml.sax.SAXParseException exception) throws org.xml.sax.SAXException {
            logger.log(Level.SEVERE, "XML Fatal Error: " + exception.getMessage());
            throw exception;
        }
    }
}